mapper.select:
SELECT id, name, color, enabled, version, created_by
FROM tag
WHERE id = #{tagId,jdbcType=OTHER}

mapper.update:
UPDATE tag
name = #{name}, color = #{color}, enabled = #{enabled}, version = version + 1
WHERE id = #{tagId,jdbcType=OTHER} AND version = #{expectedVersion}

mapper.insert:
INSERT INTO data_record_tag (record_id, tag_id, created_by) SELECT r.id, t.id, #{createdBy,jdbcType=OTHER} FROM data_record r CROSS JOIN tag t WHERE r.is_deleted = false AND t.enabled = true AND r.id IN
#{recordId,jdbcType=OTHER}
AND t.id IN
#{tagId,jdbcType=OTHER}
ON CONFLICT (record_id, tag_id) DO NOTHING

mapper.delete:
DELETE FROM data_record_tag rt USING data_record r WHERE rt.record_id = r.id AND r.is_deleted = false AND rt.record_id IN
#{recordId,jdbcType=OTHER}
AND rt.tag_id IN
#{tagId,jdbcType=OTHER}
